  1	import { type FC, useCallback, useState } from 'react';
  2	import { encode } from 'js-base64';
  3	import { FormGroupWithHelpText } from 'src/components/common/FormGroupWithHelpText/FormGroupWithHelpText';
  4	import { OpenstackSecretFieldsId } from 'src/providers/utils/constants';
  5	import { useForkliftTranslation } from 'src/utils/i18n';
  6	
  7	import { Button, ButtonVariant, InputGroup, TextInput } from '@patternfly/react-core';
  8	import { EyeIcon, EyeSlashIcon } from '@patternfly/react-icons';
  9	import type { ValidationMsg } from '@utils/validation/Validation';
 10	
 11	import { getDecodedValue } from './utils/getDecodedValue';
 12	import { openstackSecretFieldValidator } from './utils/openstackSecretFieldValidator';
 13	import type { CredentialsEditModeByTypeProps, onChangeFactoryType } from './utils/types';
 14	import OpenstackProjectEditItem from './OpenstackProjectEditItem';
 15	import OpenstackRegionEditItem from './OpenstackRegionEditItem';
 16	
 17	const ApplicationWithIDSecretFieldsEditSection: FC<CredentialsEditModeByTypeProps> = ({
 18	  onNewSecretChange,
 19	  secret,
 20	}) => {
 21	  const { t } = useForkliftTranslation();
 22	
 23	  const applicationCredentialID = getDecodedValue(secret?.data?.applicationCredentialID);
 24	  const applicationCredentialSecret = getDecodedValue(secret?.data?.applicationCredentialSecret);
 25	  const regionName = getDecodedValue(secret?.data?.regionName);
 26	  const projectName = getDecodedValue(secret?.data?.projectName);
 27	
 28	  const [passwordHidden, setPasswordHidden] = useState<boolean>(true);
 29	  const [applicationCredentialIDValidation, setApplicationCredentialIDValidation] =
 30	    useState<ValidationMsg>(
 31	      openstackSecretFieldValidator(
 32	        OpenstackSecretFieldsId.ApplicationCredentialId,
 33	        applicationCredentialID!,
 34	      ),
 35	    );
 36	  const [applicationCredentialSecretValidation, setApplicationCredentialSecretValidation] =
 37	    useState<ValidationMsg>(
 38	      openstackSecretFieldValidator(
 39	        OpenstackSecretFieldsId.ApplicationCredentialSecret,
 40	        applicationCredentialSecret!,
 41	      ),
 42	    );
 43	  const [projectNameValidation, setProjectNameValidation] = useState<ValidationMsg>(
 44	    openstackSecretFieldValidator(OpenstackSecretFieldsId.ProjectName, projectName!),
 45	  );
 46	  const [regionNameValidation, setRegionNameValidation] = useState<ValidationMsg>(
 47	    openstackSecretFieldValidator(OpenstackSecretFieldsId.RegionName, regionName!),
 48	  );
 49	
 50	  const handleChange = useCallback(
 51	    (id: OpenstackSecretFieldsId, value: string) => {
 52	      const validationState = openstackSecretFieldValidator(id, value);
 53	
 54	      if (id === OpenstackSecretFieldsId.ApplicationCredentialId)
 55	        setApplicationCredentialIDValidation(validationState);
 56	      if (id === OpenstackSecretFieldsId.ApplicationCredentialSecret)
 57	        setApplicationCredentialSecretValidation(validationState);
 58	      if (id === OpenstackSecretFieldsId.ProjectName) setProjectNameValidation(validationState);
 59	      if (id === OpenstackSecretFieldsId.RegionName) setRegionNameValidation(validationState);
 60	
 61	      const encodedValue = encode(value?.trim() ?? '');
 62	
 63	      onNewSecretChange({ ...secret, data: { ...secret.data, [id]: encodedValue } });
 64	    },
 65	    [secret, onNewSecretChange],
 66	  );
 67	
 68	  const onClickTogglePassword = () => {
 69	    setPasswordHidden(!passwordHidden);
 70	  };
 71	
 72	  const onChangeFactory: onChangeFactoryType = (changedField) => (_e, value) => {
 73	    handleChange(changedField as OpenstackSecretFieldsId, value);
 74	  };
 75	
 76	  return (
 77	    <>
 78	      <FormGroupWithHelpText
 79	        label={t('Application credential ID')}
 80	        isRequired
 81	        fieldId={OpenstackSecretFieldsId.ApplicationCredentialId}
 82	        helperText={applicationCredentialIDValidation.msg}
 83	        helperTextInvalid={applicationCredentialIDValidation.msg}
 84	        validated={applicationCredentialIDValidation.type}
 85	      >
 86	        <TextInput
 87	          spellCheck="false"
 88	          isRequired
 89	          type="text"
 90	          id={OpenstackSecretFieldsId.ApplicationCredentialId}
 91	          name={OpenstackSecretFieldsId.ApplicationCredentialId}
 92	          value={applicationCredentialID}
 93	          onChange={onChangeFactory(OpenstackSecretFieldsId.ApplicationCredentialId)}
 94	          validated={applicationCredentialIDValidation.type}
 95	        />
 96	      </FormGroupWithHelpText>
 97	
 98	      <FormGroupWithHelpText
 99	        label={t('Application credential Secret')}
100	        isRequired
101	        fieldId={OpenstackSecretFieldsId.ApplicationCredentialSecret}
102	        helperText={applicationCredentialSecretValidation.msg}
103	        helperTextInvalid={applicationCredentialSecretValidation.msg}
104	        validated={applicationCredentialSecretValidation.type}
105	      >
106	        <InputGroup>
107	          <TextInput
108	            spellCheck="false"
109	            isRequired
110	            type={passwordHidden ? 'password' : 'text'}
111	            id={OpenstackSecretFieldsId.ApplicationCredentialSecret}
112	            name={OpenstackSecretFieldsId.ApplicationCredentialSecret}
113	            value={applicationCredentialSecret}
114	            onChange={onChangeFactory(OpenstackSecretFieldsId.ApplicationCredentialSecret)}
115	            validated={applicationCredentialSecretValidation.type}
116	          />
117	          <Button
118	            variant={ButtonVariant.control}
119	            onClick={onClickTogglePassword}
120	            aria-label={passwordHidden ? 'Show password' : 'Hide password'}
121	          >
122	            {passwordHidden ? <EyeIcon /> : <EyeSlashIcon />}
123	          </Button>
124	        </InputGroup>
125	      </FormGroupWithHelpText>
126	
127	      <OpenstackRegionEditItem
128	        regionNameValidation={regionNameValidation}
129	        regionName={regionName}
130	        onChangeFactory={onChangeFactory}
131	      />
132	
133	      <OpenstackProjectEditItem
134	        projectNameValidation={projectNameValidation}
135	        projectName={projectName}
136	        onChangeFactory={onChangeFactory}
137	      />
138	    </>
139	  );
140	};
141	
142	export default ApplicationWithIDSecretFieldsEditSection;

